using UnityEngine; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.Agents { public enum DifficultyHelpType{None,ShowHint,AddMoves,EncourageRetry,ReduceTargetNextTime} public struct DifficultySuggestion{ public DifficultyHelpType helpType; public string message; public int extraMoves; public float progressRatio; public bool shouldShowHint; public static DifficultySuggestion None=>new DifficultySuggestion{helpType=DifficultyHelpType.None}; }
public class DifficultyAgent:MonoBehaviour{ [SerializeField] ScoreManager scoreManager; [SerializeField] MoveManager moveManager; [SerializeField] StageManager stageManager; [SerializeField] HintAgent hintAgent; [SerializeField,Min(0)] int failedAttemptCount; [SerializeField,Min(1)] int failThresholdForHelp=2; [SerializeField,Range(0,1)] float lowProgressRatioThreshold=.45f; [SerializeField,Min(1)] int lowMovesThreshold=5; [SerializeField,Min(1)] int suggestedExtraMoves=2; public int FailedAttemptCount=>failedAttemptCount; void Awake(){ scoreManager??=FindAnyObjectByType<ScoreManager>(); moveManager??=FindAnyObjectByType<MoveManager>(); stageManager??=FindAnyObjectByType<StageManager>(); hintAgent??=FindAnyObjectByType<HintAgent>(); } public void RegisterFailure(){failedAttemptCount++;} public void ResetFailureCount(){failedAttemptCount=0;} public DifficultySuggestion EvaluateSuggestion(){ if(stageManager==null||scoreManager==null||moveManager==null||stageManager.TargetScore<=0) return DifficultySuggestion.None; float p=GetProgressRatio(); if(moveManager.IsOutOfMoves&&scoreManager.CurrentScore<stageManager.TargetScore) return new DifficultySuggestion{helpType=DifficultyHelpType.EncourageRetry,message="Almost there. Try again!",progressRatio=p}; if(failedAttemptCount>=failThresholdForHelp) return new DifficultySuggestion{helpType=DifficultyHelpType.AddMoves,message="Need a little help? Add extra moves.",extraMoves=suggestedExtraMoves,progressRatio=p}; if(moveManager.RemainingMoves<=lowMovesThreshold&&p<lowProgressRatioThreshold) return new DifficultySuggestion{helpType=DifficultyHelpType.ShowHint,message="Try a sparkle hint!",shouldShowHint=true,progressRatio=p}; return DifficultySuggestion.None;} public bool ShouldOfferHelp()=>EvaluateSuggestion().helpType!=DifficultyHelpType.None; public float GetProgressRatio(){ return stageManager==null||scoreManager==null||stageManager.TargetScore<=0?0:Mathf.Clamp01((float)scoreManager.CurrentScore/stageManager.TargetScore);} public string GetDebugSummary()=> $"DifficultyAgent: Score={(scoreManager?scoreManager.CurrentScore:0)}, Target={(stageManager?stageManager.TargetScore:0)}, Moves={(moveManager?moveManager.RemainingMoves:0)}, Failed={failedAttemptCount}, Progress={GetProgressRatio():0.00}"; } }
